class Solution:
    def longestPalindrome(self, s: str, t: str) -> int:
        def count_odd(s):
            count = {}
            for char in s:
                count[char] = count.get(char, 0) + 1
            odd_count = sum(val % 2 for val in count.values())
            return odd_count, count

        s_odd_count, s_count = count_odd(s)
        t_odd_count, t_count = count_odd(t)

        shared_count = {}
        for char in s_count:
            if char in t_count:
                shared_count[char] = min(s_count[char], t_count[char])

        total_length = 0
        odd_found = False
        for char, count in shared_count.items():
            total_length += count * 2
            if count % 2 != 0:
                odd_found = True

        if s_odd_count > 0:
            s_odd_count -= 1
        if t_odd_count > 0:
            t_odd_count -= 1

        if s_odd_count > 0 or t_odd_count > 0:
            odd_found = True

        if odd_found:
            total_length += 1

        return total_length
```
